export const courses: Course[] = [
  {
    id: 1,
    title: 'Forex Fundamentals',
    level: 'Beginner',
    lessons: 12,
    duration: '4 hrs',
    description: 'Learn currency pairs, pips, lots, and how the forex market operates.',
    overview: 'This course gives you a solid foundation in forex trading. You will understand how currency markets work, the major and minor pairs, how to read quotes, and the mechanics of placing trades.',
    curriculum: [
      { title: 'What is the Forex Market?', duration: '18 min', content: `The foreign exchange market (forex) is the world's largest financial market, with over $7.5 trillion traded daily. Unlike stock markets, forex has no central exchange — it operates over-the-counter (OTC) 24 hours a day, 5 days a week across global financial centers.\n\n**Key participants:**\n- Central banks (e.g. Federal Reserve, ECB)\n- Commercial banks\n- Hedge funds and institutional investors\n- Retail traders (you)\n\n**Why trade forex?**\n- Unmatched liquidity\n- 24/5 market access\n- Low barriers to entry\n- Ability to profit in both rising and falling markets via going long or short\n\nThe forex market is driven by macroeconomic forces: interest rates, inflation, GDP growth, political stability, and trade flows between countries.` },
      { title: 'Major, Minor & Exotic Pairs', duration: '22 min', content: `Currency pairs are quoted as one currency against another. The first currency is the **base**, the second is the **quote**.\n\nExample: EUR/USD = 1.0850 means 1 Euro buys 1.0850 US Dollars.\n\n**Major pairs** (most traded, tightest spreads):\n- EUR/USD — Euro / US Dollar\n- GBP/USD — British Pound / US Dollar\n- USD/JPY — US Dollar / Japanese Yen\n- USD/CHF — US Dollar / Swiss Franc\n- AUD/USD — Australian Dollar / US Dollar\n- USD/CAD — US Dollar / Canadian Dollar\n- NZD/USD — New Zealand Dollar / US Dollar\n\n**Minor pairs** — pairs that don't include USD:\n- EUR/GBP, EUR/JPY, GBP/JPY\n\n**Exotic pairs** — one major currency paired with an emerging market currency:\n- USD/TRY (Turkish Lira), USD/ZAR (South African Rand)\n- Higher spreads, more volatile, harder to trade` },
      { title: 'Understanding Pips, Lots & Leverage', duration: '25 min', content: `**Pip** — the smallest standard price movement in a currency pair.\n- Most pairs: 4th decimal place (0.0001)\n- JPY pairs: 2nd decimal place (0.01)\n\nExample: EUR/USD moves from 1.0850 to 1.0855 = 5 pips\n\n**Lot sizes:**\n| Type | Units | Pip Value (EUR/USD) |\n|------|-------|---------------------|\n| Standard | 100,000 | ~$10 |\n| Mini | 10,000 | ~$1 |\n| Micro | 1,000 | ~$0.10 |\n\n**Leverage** amplifies your buying power:\n- 1:100 leverage = control $10,000 with $100 margin\n- Doubles profits AND losses\n- New traders should use 1:10 or lower\n\n⚠️ Leverage is a double-edged sword. Never risk more than 1-2% of your account per trade.` },
      { title: 'Reading Forex Quotes & Spreads', duration: '20 min', content: `Every forex quote has two prices: **Bid** and **Ask**.\n\n- **Bid** — the price your broker buys from you (you sell at bid)\n- **Ask** — the price your broker sells to you (you buy at ask)\n- **Spread** = Ask − Bid (the broker's profit)\n\nExample: EUR/USD Bid: 1.08495 / Ask: 1.08510\nSpread = 1.5 pips\n\n**Spread types:**\n- Fixed spreads — stay constant regardless of market conditions\n- Variable (floating) spreads — widen during news events or low liquidity\n\n**When does spread widen?**\n- Major news releases (NFP, CPI, rate decisions)\n- Market open/close\n- Low liquidity periods (late Friday, Asian session for EUR/USD)\n\nAlways factor spread into your entry: if you buy EUR/USD at 1.08510, you're instantly down 1.5 pips.` },
      { title: 'Market Sessions: London, New York, Tokyo', duration: '18 min', content: `Forex trades 24 hours, but activity is not equal across all hours. There are 3 major sessions:\n\n**Tokyo Session (Asian):** 00:00 – 09:00 GMT\n- Quieter, lower volatility\n- Best for: JPY, AUD, NZD pairs\n\n**London Session:** 08:00 – 17:00 GMT\n- Most active session — ~35% of all volume\n- Best for: EUR, GBP pairs\n- Big moves often start here\n\n**New York Session:** 13:00 – 22:00 GMT\n- Second most active — ~20% of volume\n- USD pairs most active\n- US economic data released here (NFP, CPI)\n\n**Overlap (Best time to trade):**\nLondon + New York overlap: 13:00 – 17:00 GMT\n- Highest liquidity, tightest spreads, most opportunities\n\nAs a retail trader, focus your trading during the London open and London/NY overlap.` },
      { title: 'Order Types: Market, Limit, Stop', duration: '20 min', content: `Understanding order types is essential for executing your strategy precisely.\n\n**Market Order** — executes immediately at current price\n- Use when: you want instant entry\n- Risk: slippage during fast markets\n\n**Limit Order** — executes at a specific price or better\n- Buy Limit: buy at a price BELOW current price\n- Sell Limit: sell at a price ABOVE current price\n- Use when: you want to enter at a specific level\n\n**Stop Order** — executes when price reaches a trigger level\n- Buy Stop: buy when price moves ABOVE a level (breakout)\n- Sell Stop: sell when price moves BELOW a level\n- Stop Loss: automatically closes losing trades\n- Take Profit: automatically closes winning trades\n\n**Best practice:** Always use Stop Loss and Take Profit when entering a trade. Never trade without a stop loss.` },
      { title: 'Your First Demo Trade', duration: '30 min', content: `Before risking real money, practice on a demo account. All major brokers offer free demo accounts with virtual funds.\n\n**Steps to place your first trade:**\n\n1. Open your broker platform (MT4/MT5 or web platform)\n2. Select a currency pair (start with EUR/USD)\n3. Check the current price and spread\n4. Decide your direction: Buy (bullish) or Sell (bearish)\n5. Choose your lot size (start with 0.01 micro lot)\n6. Set your Stop Loss (e.g. 20 pips below entry)\n7. Set your Take Profit (e.g. 40 pips above entry = 1:2 R:R)\n8. Click Buy/Sell\n\n**What to observe:**\n- How the P&L changes tick by tick\n- The effect of spread on your entry\n- How stop loss protects you\n\nSpend at least 2 weeks on demo before considering a live account. Consistency on demo is the baseline.` },
      { title: 'How Brokers Work', duration: '20 min', content: `Your broker is the intermediary between you and the forex market. Understanding how they work protects you.\n\n**Broker types:**\n\n**Market Maker (Dealing Desk):**\n- Takes the opposite side of your trade\n- Creates a conflict of interest\n- Wider spreads but fixed\n- Good for beginners (no commission)\n\n**ECN/STP (No Dealing Desk):**\n- Passes your orders directly to liquidity providers\n- Tighter spreads + commission per trade\n- Better for scalping and high-frequency trading\n\n**What to look for in a broker:**\n- Regulation (FCA, ASIC, CySEC, NFA)\n- Segregated client funds\n- Fast execution, low slippage\n- Competitive spreads\n- Reliable platform (MT4/MT5)\n- Responsive support\n\n⚠️ Avoid unregulated brokers. Always verify a broker's license on the regulator's official website.` },
      { title: 'Fundamental vs Technical Analysis', duration: '22 min', content: `There are two main schools of thought for analyzing the forex market:\n\n**Fundamental Analysis:**\n- Studies economic data, news, central bank policy\n- Key indicators: interest rates, inflation (CPI), GDP, employment (NFP)\n- Longer time horizon — positions held for days to weeks\n- Example: If the US raises interest rates, USD typically strengthens\n\n**Technical Analysis:**\n- Studies price charts, patterns, and indicators\n- Based on the idea that all information is already reflected in price\n- Works across all time frames\n- Example: Price bounces at a key support level → buy signal\n\n**Which is better?**\nMost professional traders use both:\n- Fundamentals determine the *direction* (macro bias)\n- Technical analysis determines the *entry and exit*\n\nStart by mastering technical analysis — it gives you precise, actionable signals with clear risk management rules.` },
      { title: 'Economic Indicators Overview', duration: '25 min', content: `Economic data releases move the forex market. Here are the most important ones:\n\n**US Indicators (highest impact):**\n- **NFP (Non-Farm Payrolls)** — Monthly jobs report. Released first Friday of each month. Massive mover for USD pairs.\n- **CPI (Consumer Price Index)** — Inflation measure. High CPI → rate hikes → stronger USD\n- **Fed Funds Rate** — Federal Reserve interest rate decision\n- **GDP** — Quarterly economic growth\n- **ISM Manufacturing/Services PMI**\n\n**Other key indicators:**\n- ECB rate decision (EUR)\n- BOE rate decision (GBP)\n- BOJ rate decision (JPY)\n- Australian employment data (AUD)\n\n**How to use them:**\nUse an economic calendar (Forex Factory, Investing.com) to track upcoming releases. Avoid trading 15 minutes before/after high-impact news unless you have a specific news-trading strategy.` },
      { title: 'Building a Trading Routine', duration: '18 min', content: `Consistency is the foundation of profitable trading. A structured routine removes emotion and improves decision-making.\n\n**Daily routine example:**\n\n**Pre-market (30 mins before London open):**\n- Check economic calendar for the day\n- Review higher time frame charts (Daily, 4H)\n- Identify key support/resistance levels\n- Note any open positions\n\n**During session:**\n- Monitor price action at key levels\n- Only trade your pre-defined setups\n- Log every trade in your journal\n\n**Post-session review (30 mins):**\n- Review all trades taken\n- What went right? What went wrong?\n- Update your journal\n\n**Weekly review (Sunday, 1 hour):**\n- Review the week's performance\n- Identify patterns in your mistakes\n- Set goals for the coming week\n\nA trading journal is non-negotiable. You cannot improve what you don't measure.` },
      { title: 'Final Assessment', duration: '15 min', content: `Congratulations on completing Forex Fundamentals! 🎉\n\n**Key takeaways from this course:**\n\n✅ The forex market is a 24/5 OTC market with $7.5T daily volume\n✅ Major pairs have the tightest spreads and most liquidity\n✅ A pip is the smallest price movement; standard lot = 100,000 units\n✅ Always trade with a Stop Loss — no exceptions\n✅ The London/NY overlap (13:00-17:00 GMT) offers the best opportunities\n✅ Use a demo account until you're consistently profitable\n✅ Never trade without checking the economic calendar\n✅ Keep a trading journal from day one\n\n**Your next steps:**\n1. Open a demo account with a regulated broker\n2. Practice placing trades for at least 2 weeks\n3. Proceed to Technical Analysis Mastery\n\nYou now have the foundation. The journey to profitable trading starts with consistent practice. Good luck! 🚀` },
    ],
  },
  {
    id: 2,
    title: 'Technical Analysis Mastery',
    level: 'Intermediate',
    lessons: 18,
    duration: '7 hrs',
    description: 'Chart patterns, support & resistance, indicators, and candlestick analysis.',
    overview: 'Go deep into reading price charts. Master candlestick patterns, key chart formations, and how to use indicators like RSI, MACD and Bollinger Bands to time your entries and exits.',
    curriculum: [
      { title: 'Introduction to Technical Analysis', duration: '20 min', content: `Technical analysis is the study of past price action to predict future price movements. It operates on three core assumptions:\n\n1. **Price discounts everything** — all known information is already reflected in the price\n2. **Price moves in trends** — prices tend to move in directional trends rather than randomly\n3. **History repeats itself** — traders react similarly to similar situations, creating repeating patterns\n\n**Why technical analysis works in forex:**\n- Forex is driven heavily by trader psychology and institutional positioning\n- Key levels (support/resistance) are watched by thousands of traders simultaneously — creating self-fulfilling prophecies\n- Patterns repeat because human psychology is consistent\n\n**Time frames:**\n- Monthly/Weekly: macro trend direction\n- Daily/4H: trade direction and key levels\n- 1H/15M: entry and exit timing\n\nAlways start your analysis top-down: higher time frames first, then drill down for entry.` },
      { title: 'Candlestick Patterns: Basics', duration: '25 min', content: `Candlesticks originated in Japan in the 18th century. Each candle shows 4 prices:\n- **Open** — price at start of period\n- **High** — highest price reached\n- **Low** — lowest price reached\n- **Close** — price at end of period\n\n**Bullish candle:** Close > Open (usually green/white)\n**Bearish candle:** Close < Open (usually red/black)\n\n**Key basic patterns:**\n\n**Doji** — Open ≈ Close, indicates indecision\n- Signals potential reversal at key levels\n\n**Hammer** — Small body, long lower wick, at bottom of downtrend\n- Bullish reversal signal\n\n**Shooting Star** — Small body, long upper wick, at top of uptrend\n- Bearish reversal signal\n\n**Engulfing Patterns:**\n- Bullish Engulfing: large bullish candle engulfs previous bearish candle\n- Bearish Engulfing: large bearish candle engulfs previous bullish candle\n\nCandlestick patterns are most reliable at key support/resistance levels, not in the middle of a range.` },
      { title: 'Candlestick Patterns: Advanced', duration: '28 min', content: `Advanced candlestick patterns provide higher-probability signals when they appear at key levels.\n\n**Morning Star** (3-candle bullish reversal):\n1. Large bearish candle\n2. Small indecision candle (gap down)\n3. Large bullish candle closing above midpoint of candle 1\n\n**Evening Star** (3-candle bearish reversal):\nOpposite of Morning Star — appears at tops\n\n**Three White Soldiers** (strong bullish continuation):\n3 consecutive bullish candles, each closing near its high\n\n**Three Black Crows** (strong bearish continuation):\n3 consecutive bearish candles, each closing near its low\n\n**Harami** (inside bar):\n- Small candle contained within previous large candle\n- Signals momentum loss and potential reversal\n\n**Pin Bar (Rejection Candle):**\n- Long wick (2-3x body length) showing strong rejection\n- One of the highest-probability single-candle signals\n- Bullish pin: long lower wick rejecting support\n- Bearish pin: long upper wick rejecting resistance\n\n**Rule:** Never trade candlestick patterns in isolation. Always combine with support/resistance and trend direction.` },
      { title: 'Support & Resistance Levels', duration: '30 min', content: `Support and resistance are the most fundamental concepts in technical analysis.\n\n**Support** — a price level where buying pressure has historically exceeded selling pressure, causing price to bounce up.\n\n**Resistance** — a price level where selling pressure has historically exceeded buying pressure, causing price to fall.\n\n**How to identify them:**\n- Look for price levels where the market has reversed multiple times\n- Rounder numbers (1.0800, 1.1000) tend to be strong psychological levels\n- Previous highs become resistance; previous lows become support\n\n**Role reversal:**\nWhen price breaks through a resistance level, that level often becomes new support — and vice versa. This is one of the most powerful concepts in TA.\n\n**Strength of a level increases with:**\n- Number of times price has tested and respected it\n- Time between tests\n- Volume at the level\n- Higher time frame confirmation\n\n**Trading approach:**\n- Buy at support with stop below it\n- Sell at resistance with stop above it\n- Wait for confirmation candle before entering` },
      { title: 'Trend Lines & Channels', duration: '22 min', content: `Trend lines visually represent the direction and momentum of price movement.\n\n**Drawing a valid trend line:**\n- Bullish trend line: connect at least 2 higher lows (draw below price)\n- Bearish trend line: connect at least 2 lower highs (draw above price)\n- 3+ touches = high-confidence trend line\n\n**Trading trend lines:**\n- Buy when price pulls back to bullish trend line\n- Sell when price pulls back to bearish trend line\n- A break of a trend line signals potential trend change\n\n**Price Channels:**\nDraw a parallel line to your trend line connecting the highs (bull channel) or lows (bear channel).\n- Upper channel line = resistance\n- Lower channel line = support\n- Price oscillates between the two lines\n\n**Channel trading strategy:**\n1. Identify the channel\n2. Buy near the lower channel line in an uptrend\n3. Sell near the upper channel line in a downtrend\n4. Exit when price breaks out of the channel\n\nChannel breakouts often lead to strong directional moves equal to the width of the channel.` },
      { title: 'Chart Patterns: Head & Shoulders', duration: '25 min', content: `The Head & Shoulders is one of the most reliable reversal patterns in technical analysis.\n\n**Structure:**\n- Left Shoulder: price rises, peaks, then falls\n- Head: price rises to a higher peak, then falls\n- Right Shoulder: price rises to a similar level as the left shoulder, then falls\n- Neckline: a support line connecting the two troughs\n\n**Trading the pattern:**\n1. Wait for the right shoulder to form\n2. Enter short when price breaks below the neckline\n3. Stop loss: above the right shoulder\n4. Target: neckline − distance from neckline to head\n\n**Inverse Head & Shoulders** (bullish version):\n- Same pattern upside down at the bottom of a downtrend\n- Entry: buy when price breaks above neckline\n\n**Key notes:**\n- Volume should decrease from left shoulder to head to right shoulder\n- Volume increases on the neckline breakout (confirmation)\n- Pattern is only complete when neckline breaks — don't enter early\n- The pattern fails if price reclaims the neckline after breaking it` },
      { title: 'Chart Patterns: Flags & Pennants', duration: '22 min', content: `Flags and pennants are powerful continuation patterns that signal the trend will resume after a brief consolidation.\n\n**Bull Flag:**\n- Strong upward move (the flagpole)\n- Followed by a downward-sloping consolidation channel (the flag)\n- Entry: buy when price breaks above the upper flag channel\n- Target: add the flagpole length to the breakout point\n\n**Bear Flag:**\n- Strong downward move (the flagpole)\n- Followed by an upward-sloping consolidation\n- Entry: sell when price breaks below the lower channel\n\n**Bull Pennant:**\n- Strong upward move\n- Followed by converging trend lines (symmetrical triangle)\n- Entry: buy the breakout above the triangle\n\n**Key characteristics:**\n- Consolidation should be relatively shallow (30-50% of flagpole)\n- Volume decreases during consolidation\n- Volume expands on breakout\n- The more powerful the initial move, the more reliable the pattern\n\n**Time consideration:** Flags that take 5-20 candles to form are most reliable. Anything longer may indicate a more significant reversal.` },
      { title: 'Moving Averages', duration: '25 min', content: `Moving averages smooth out price data to reveal the underlying trend direction.\n\n**Simple Moving Average (SMA):**\n- Equally weighted average of closing prices over N periods\n- 50 SMA and 200 SMA are watched by institutional traders\n\n**Exponential Moving Average (EMA):**\n- Gives more weight to recent prices\n- More responsive to recent price action\n- Common: 8 EMA, 21 EMA, 50 EMA, 200 EMA\n\n**Trading with MAs:**\n\n1. **Trend filter:** Price above 200 EMA = bullish bias; below = bearish\n2. **Dynamic support/resistance:** In strong trends, 21 EMA often acts as support\n3. **MA Crossover:** When fast MA crosses above slow MA = bullish signal (Golden Cross)\n4. **Death Cross:** When 50 SMA crosses below 200 SMA = bearish signal\n\n**Common MA strategies:**\n- 8/21 EMA crossover for swing trading\n- 50/200 SMA for long-term trend direction\n- Pullback to 21 EMA in strong trends for entries\n\n**Limitation:** MAs are lagging indicators — they react to price, they don't predict it. Use them to confirm trend direction, not as standalone buy/sell signals.` },
      { title: 'RSI & Stochastic Oscillator', duration: '25 min', content: `Momentum oscillators measure the speed and strength of price movements.\n\n**RSI (Relative Strength Index):**\n- Scale: 0–100\n- Above 70 = overbought (potential reversal down)\n- Below 30 = oversold (potential reversal up)\n- Setting: 14 periods (default)\n\n**RSI Divergence (most powerful use):**\n- Bullish divergence: price makes lower low, RSI makes higher low → momentum reversal\n- Bearish divergence: price makes higher high, RSI makes lower high → weakening momentum\n\n**Stochastic Oscillator:**\n- Scale: 0–100 (two lines: %K and %D)\n- Above 80 = overbought\n- Below 20 = oversold\n- Buy signal: %K crosses above %D in oversold zone\n- Sell signal: %K crosses below %D in overbought zone\n\n**Key warning:**\nIn strong trending markets, RSI can stay overbought/oversold for extended periods. Using RSI alone to counter-trend trade is dangerous.\n\n**Best use:** Combine with support/resistance. A bullish pin bar at support + RSI oversold = high probability buy setup.` },
      { title: 'MACD Deep Dive', duration: '28 min', content: `MACD (Moving Average Convergence Divergence) is a trend-following momentum indicator.\n\n**Components:**\n- MACD Line: 12 EMA − 26 EMA\n- Signal Line: 9 EMA of MACD line\n- Histogram: MACD Line − Signal Line\n\n**Standard settings:** 12, 26, 9\n\n**Signals:**\n\n1. **Crossover:** MACD line crosses above signal line = bullish; below = bearish\n2. **Zero line cross:** MACD crossing above zero confirms uptrend; below zero confirms downtrend\n3. **Histogram:** Growing histogram = increasing momentum; shrinking = weakening momentum\n\n**MACD Divergence:**\n- Bullish: price makes lower low, MACD histogram makes higher low\n- One of the most reliable reversal signals in forex\n\n**Best time frames:** Daily and 4H charts produce the most reliable MACD signals.\n\n**Limitation:** MACD is a lagging indicator. On shorter time frames (15M, 5M), signals come too late for most traders. Use it for confirmation, not as a sole entry signal.` },
      { title: 'Bollinger Bands', duration: '22 min', content: `Bollinger Bands measure volatility and identify overbought/oversold conditions relative to recent price action.\n\n**Components:**\n- Middle Band: 20-period SMA\n- Upper Band: Middle + 2 standard deviations\n- Lower Band: Middle − 2 standard deviations\n\n**Key concepts:**\n\n**Band squeeze:** When bands narrow = low volatility = explosive move imminent. The direction of the breakout determines the trade.\n\n**Band expansion:** When bands widen = high volatility = strong trending conditions\n\n**Bounce strategy (ranging markets):**\n- Price touching lower band + bullish candle = buy\n- Price touching upper band + bearish candle = sell\n- Target: opposite band or middle band\n\n**Breakout strategy (trending markets):**\n- Price closing outside the upper band repeatedly = strong uptrend, look to buy pullbacks\n- Walking the bands = continuation of strong trend\n\n**Warning:** In strong trends, price can "walk the band" — continuously touching the upper (or lower) band without reversing. Always check the overall trend before fading band touches.` },
      { title: 'Fibonacci Retracements', duration: '25 min', content: `Fibonacci retracement levels are horizontal lines that indicate potential support and resistance areas based on the Fibonacci sequence.\n\n**Key levels:** 23.6%, 38.2%, 50%, 61.8%, 78.6%\n\nThe 61.8% level (the "Golden Ratio") is the most significant and most watched by institutional traders.\n\n**How to draw Fibonacci:**\n1. Identify a significant swing high and swing low\n2. In an uptrend: draw from swing low to swing high\n3. In a downtrend: draw from swing high to swing low\n4. The retracement levels become potential buy/sell zones\n\n**Trading strategy:**\n- In an uptrend, wait for price to pull back to the 38.2%, 50%, or 61.8% level\n- Look for bullish confirmation (pin bar, engulfing, RSI oversold)\n- Enter long with stop below the next Fibonacci level\n- Target: previous high or 161.8% extension\n\n**Why it works:** Fibonacci levels are self-fulfilling. Millions of traders watch these exact same levels, causing reactions at them.\n\n**Fibonacci extensions** (target levels): 127.2%, 161.8%, 261.8% — used to project where price may go after a retracement.` },
      { title: 'Volume Analysis', duration: '20 min', content: `Volume represents the number of units traded in a given period. In forex, volume data is less precise than in stocks (no central exchange), but **tick volume** (number of price changes) is a reliable proxy.\n\n**Key volume principles:**\n\n1. **Trend + high volume = conviction** — a strong move on high volume is more likely to continue\n2. **Trend + low volume = weakness** — the move may reverse\n3. **Breakout + high volume = valid** — confirms the breakout\n4. **Breakout + low volume = false** — likely to fail and reverse\n\n**Volume at support/resistance:**\n- High volume at support: strong buying interest, level likely to hold\n- High volume at resistance: strong selling interest, level likely to hold\n\n**Volume Spread Analysis (VSA):**\n- Wide spread + high volume + bullish close = accumulation (smart money buying)\n- Wide spread + high volume + bearish close = distribution (smart money selling)\n- Narrow spread + high volume = absorption (one side absorbing the other)\n\nVolume is most useful as confirmation — use it to validate signals from price action and other indicators.` },
      { title: 'Multi-Timeframe Analysis', duration: '25 min', content: `Multi-timeframe analysis (MTFA) is the process of analyzing the same currency pair across different time frames to get a complete picture of the market.\n\n**The Top-Down Approach:**\n1. **Weekly/Daily** — identify the major trend and key structure levels\n2. **4H** — identify intermediate trend, set up trades in direction of higher TF\n3. **1H/15M** — find precise entry, stop and target\n\n**Example workflow:**\n- Daily chart: EUR/USD in uptrend, pulling back to 50 EMA\n- 4H chart: forming a bullish flag pattern\n- 1H chart: bullish pin bar at the 4H flag support\n→ High-probability buy setup with 3 time frame confluence\n\n**Rules of MTFA:**\n- Never trade against the higher time frame trend without a very clear reversal signal\n- The higher the time frame, the more significant the support/resistance level\n- Use higher TFs to filter trades — only take 1H signals that align with the 4H and Daily trend\n\n**Common mistake:** Trading 5M charts without checking the 1H or 4H. A "perfect" 5M setup can fail instantly if it's against a strong 1H trend.` },
      { title: 'Building a Technical Strategy', duration: '30 min', content: `A complete trading strategy needs three components: **Entry, Stop Loss, and Take Profit**. Every trade must have all three defined BEFORE entry.\n\n**Strategy template:**\n\n**Entry conditions (need ALL to be true):**\n- Higher TF trend is bullish (price above 50 EMA on Daily)\n- Price has pulled back to key support level\n- Bullish confirmation candle (pin bar or engulfing) on 4H or 1H\n- RSI is below 50 or showing bullish divergence\n\n**Stop Loss:** Below the key support level (below the candle's low)\n\n**Take Profit:** Next resistance level or 2:1 RR minimum\n\n**Example entry checklist (EUR/USD Long):**\n☐ Daily trend bullish (above 200 EMA)\n☐ Price at daily support or Fibonacci level\n☐ 4H bullish pin bar or engulfing\n☐ RSI between 30-50 on 4H\n☐ Stop: 10-15 pips below support\n☐ Target: 20-30 pips (2:1 RR)\n\n**Backtesting:** Apply your strategy to at least 6 months of historical data before trading live. A valid strategy should have:\n- Win rate above 40% (with 2:1 RR, 40% win rate = profitable)\n- Maximum drawdown under 20%\n- At least 50 sample trades` },
      { title: 'Backtesting Your Setup', duration: '25 min', content: `Backtesting is testing your strategy on historical price data to evaluate its performance before risking real money.\n\n**Manual backtesting steps:**\n1. Open a chart, go back in time to start of your test period\n2. Scroll forward candle by candle\n3. When your setup criteria are met, record the trade (entry, SL, TP)\n4. Record the outcome (win/loss/breakeven)\n5. Repeat for 50-100 trades minimum\n\n**Key metrics to track:**\n- **Win rate** — percentage of winning trades\n- **Average RR** — average reward vs risk per trade\n- **Expectancy** = (Win% × Avg Win) − (Loss% × Avg Loss)\n- **Maximum drawdown** — largest peak-to-trough equity decline\n- **Profit factor** = Gross profit / Gross loss (target >1.5)\n\n**Tools:**\n- TradingView: use replay feature for manual backtesting\n- MT4/MT5 Strategy Tester: for automated EA testing\n\n**Pitfall: Curve fitting**\nDon't optimize your strategy to fit past data perfectly — it won't work in live markets. Test on out-of-sample data (data you didn't use to build the strategy).` },
      { title: 'Live Chart Walkthroughs', duration: '35 min', content: `Let's walk through real chart examples applying everything learned in this course.\n\n**Example 1: EUR/USD Swing Long**\n- Daily: uptrend, price pulling back to 61.8% Fibonacci\n- 4H: bullish engulfing candle at Fibonacci level\n- 4H RSI: 42 (neutral, room to run)\n- Entry: 1.0850, Stop: 1.0810 (40 pips), Target: 1.0930 (80 pips)\n- Result: 2:1 RR setup ✓\n\n**Example 2: GBP/USD Short**\n- Daily: downtrend, price rallying to resistance\n- 4H: bearish pin bar at previous support-turned-resistance\n- MACD: crossing below signal line\n- Entry: 1.2650, Stop: 1.2690 (40 pips), Target: 1.2570 (80 pips)\n- Result: 2:1 RR setup ✓\n\n**Example 3: USD/JPY Breakout**\n- Daily: range-bound between 148.00 and 151.00\n- 4H: price consolidating in bull flag below resistance\n- Volume: increasing on the consolidation days\n- Entry: 151.10 (break of range), Stop: 150.50 (60 pips), Target: 152.20 (110 pips)\n- Result: Breakout play ✓\n\n**Key takeaway:** These setups didn't require perfect conditions — they required multiple confluences aligning.` },
      { title: 'Final Assessment', duration: '15 min', content: `Congratulations on completing Technical Analysis Mastery! 🎉\n\n**Key takeaways:**\n\n✅ Candlestick patterns + key levels = high-probability signals\n✅ Support becomes resistance, resistance becomes support\n✅ Always analyze top-down: Daily → 4H → 1H\n✅ Moving averages define trend; oscillators time entries\n✅ RSI divergence is one of the strongest reversal signals\n✅ Bollinger Band squeeze precedes explosive moves\n✅ Fibonacci 61.8% is the "golden" retracement level\n✅ Every strategy needs entry, stop loss, and take profit rules\n✅ Backtest before trading live — 50 trades minimum\n\n**Your next steps:**\n1. Build your personal trading strategy using the template\n2. Backtest it on 3-6 months of data\n3. Paper trade for 2 weeks\n4. Proceed to Risk Management & Psychology\n\nYou now have the technical toolkit. Apply it consistently. 🚀` },
    ],
  },
  {
    id: 3,
    title: 'Risk Management & Psychology',
    level: 'Intermediate',
    lessons: 10,
    duration: '3 hrs',
    description: 'Position sizing, drawdown control, and the mindset of a professional trader.',
    overview: 'The difference between winning and losing traders is often risk management and mental discipline. This course teaches you how to protect your capital and stay consistent under pressure.',
    curriculum: [
      { title: 'Why Most Traders Fail', duration: '20 min', content: `Studies consistently show that 70-80% of retail forex traders lose money. Understanding why is the first step to being in the profitable minority.\n\n**Top reasons traders fail:**\n\n1. **No edge** — trading random setups without a tested strategy\n2. **Poor risk management** — risking too much per trade\n3. **Overleveraging** — using 1:500 leverage on small accounts\n4. **Revenge trading** — doubling down after losses to "get even"\n5. **Lack of patience** — forcing trades when no setup is present\n6. **Moving stop losses** — letting losses run beyond plan\n7. **No trading plan** — trading on emotion and impulse\n8. **Unrealistic expectations** — expecting 100% monthly returns\n\n**The uncomfortable truth:**\nTrading is a skill that takes years to develop. The traders who succeed treat it like a business, not a casino. They manage risk first, seek profit second.\n\n**What successful traders do differently:**\n- They have a written trading plan\n- They risk a fixed small percentage per trade\n- They keep a detailed trading journal\n- They focus on process, not P&L\n- They continuously learn and adapt` },
      { title: 'The Risk/Reward Ratio', duration: '22 min', content: `The Risk/Reward Ratio (RR) is the potential profit of a trade divided by its potential loss.\n\n**RR = Target Size ÷ Stop Loss Size**\n\nExample: Stop loss 20 pips, take profit 40 pips = 1:2 RR\n\n**Why RR matters:**\n\nWith a 1:2 RR, you only need to win 34% of your trades to break even:\n- 10 trades: 4 wins (4 × 2R = +8R), 6 losses (6 × 1R = -6R) = +2R profit\n\n| Win Rate | RR Required to be Profitable |\n|----------|------------------------------|\n| 30% | 1:2.4 or better |\n| 40% | 1:1.5 or better |\n| 50% | 1:1.01 or better |\n| 60% | Any positive RR |\n\n**Minimum standard:** Never take a trade with less than 1:1.5 RR. Aim for 1:2 or higher.\n\n**Common mistake:** Taking 1:0.5 RR trades because they have a "high win rate." A 70% win rate with 1:0.5 RR is still unprofitable (70×0.5 - 30×1 = 35 - 30 = +5R over 100 trades — barely profitable after spread).\n\nA high RR gives you a larger margin for error.` },
      { title: 'Position Sizing & Lot Calculation', duration: '25 min', content: `Position sizing determines how many lots to trade based on your risk per trade. This is the most critical skill in forex.\n\n**The 1-2% Rule:**\nNever risk more than 1-2% of your account on a single trade.\n- $1,000 account × 2% = $20 max risk per trade\n- $10,000 account × 1% = $100 max risk per trade\n\n**Position size formula:**\n\nLot Size = (Account × Risk%) ÷ (Stop Loss in pips × Pip Value)\n\n**Example:**\n- Account: $5,000\n- Risk: 1% = $50\n- Stop Loss: 25 pips\n- EUR/USD pip value (standard lot): $10\n- Lot Size = $50 ÷ (25 × $10) = $50 ÷ $250 = 0.20 lots\n\n**Why this is essential:**\nWith 1% risk per trade, you'd need to lose 100 consecutive trades to blow your account. In reality, even poor strategies rarely produce more than 10 consecutive losses.\n\n**Tools:** Use a forex position size calculator (available on myfxbook.com or your broker platform) until you can calculate it mentally.\n\n⚠️ Fixed lot trading (always 0.1 lots) is amateur behavior. Professional traders always size based on stop loss distance.` },
      { title: 'Setting Stop Losses & Take Profits', duration: '22 min', content: `Stop losses and take profits should be set based on market structure, not arbitrary pip amounts.\n\n**Stop Loss placement rules:**\n\n1. **Structure-based stops:** Place below the nearest support level (for longs) or above resistance (for shorts)\n2. **Give it room:** Don't place stops at exact support — place them a few pips beyond to avoid being stopped out by normal fluctuation (noise)\n3. **ATR-based stops:** Use Average True Range (ATR) to measure normal market movement. Stop = 1-1.5 × ATR below entry\n\n**Never:**\n- Place stops at round numbers (they're too obvious)\n- Move stops further away when the trade goes against you\n- Trade without a stop loss\n\n**Take Profit placement:**\n- Next significant resistance (for longs) or support (for shorts)\n- Fibonacci extension levels (127.2%, 161.8%)\n- 2:1 or 3:1 RR from entry\n\n**Trailing stops:**\nAs the trade moves in your favor, move the stop to lock in profits:\n1. Move stop to breakeven once trade reaches 1:1\n2. Trail stop behind each new support level as price advances\n\nA trailing stop lets profits run while protecting against reversal.` },
      { title: 'Managing Drawdown', duration: '20 min', content: `Drawdown is the reduction in your account balance from its peak to its trough. Every trader experiences drawdown — the goal is to manage it.\n\n**Types of drawdown:**\n- **Absolute drawdown:** Loss from initial account balance\n- **Maximum drawdown:** Largest peak-to-trough during a period\n- **Relative drawdown:** Maximum drawdown as % of peak balance\n\n**Drawdown recovery math (the brutal truth):**\n| Drawdown | Recovery needed |\n|----------|----------------|\n| 10% | 11.1% |\n| 25% | 33.3% |\n| 50% | 100% |\n| 75% | 300% |\n\nA 50% drawdown requires 100% gain just to break even. This is why protecting capital is more important than chasing profits.\n\n**Drawdown rules:**\n- If you hit 10% drawdown in a day: stop trading for the day\n- If you hit 20% drawdown in a week: reduce position size by 50%\n- If you hit 30% drawdown total: pause and review strategy\n\n**Correlation risk:** Trading multiple pairs that are highly correlated (EUR/USD and GBP/USD both move with USD) multiplies your risk. If you're long both, you effectively have double exposure to a USD move.` },
      { title: 'The Psychology of Losses', duration: '25 min', content: `Losses are inevitable in trading. A 60% win rate is considered excellent. Learning to handle losses without emotional reaction is what separates professionals from amateurs.\n\n**How losses affect decision-making:**\n\nLoss aversion (Kahneman & Tversky): Humans feel the pain of a loss roughly 2× more intensely than the pleasure of an equivalent gain. This causes traders to:\n- Hold losing trades too long (hoping for recovery)\n- Cut winning trades too early (fear of giving back gains)\n\n**Common psychological traps:**\n\n**Hope trading:** Staying in a losing trade hoping it will come back\n→ Solution: Stop loss eliminates hope trading\n\n**Fear of missing out (FOMO):** Chasing a move you missed\n→ Solution: There's always another setup. Missed trades are free. Bad entries cost money.\n\n**Overconfidence after wins:** Increasing risk after a winning streak\n→ Solution: Maintain fixed risk % regardless of recent results\n\n**The acceptance mindset:**\nAccept that each trade's outcome is uncertain. Your job is to execute your plan perfectly — not to win every trade. Detach from outcomes, focus on process.` },
      { title: 'Overcoming Revenge Trading', duration: '20 min', content: `Revenge trading is entering a trade impulsively to recover a previous loss — one of the fastest ways to blow a trading account.\n\n**The revenge trading cycle:**\nLoss → frustration → impulsive entry → bigger loss → more frustration → larger impulsive entry → account blown\n\n**Warning signs you're revenge trading:**\n- Entering a trade within minutes of a stop out\n- Increasing lot size after a loss\n- Deviating from your strategy\n- Feeling angry or desperate\n- Thinking "I need to make this money back"\n\n**How to break the cycle:**\n\n1. **Walk away rule:** After any loss, step away from the screen for at least 30 minutes\n2. **Daily loss limit:** If you hit 2-3% account loss in a day, shut down the platform\n3. **Journal the emotion:** Write down what you're feeling after a loss — this creates self-awareness\n4. **Reframe losses:** A properly executed losing trade is not a failure. Following your plan is a success regardless of outcome.\n5. **Reduce size:** If on a losing streak, cut position size in half until confidence returns\n\nThe market will be there tomorrow. Your capital won't be if you revenge trade.` },
      { title: 'Building a Trading Journal', duration: '22 min', content: `A trading journal is your most powerful improvement tool. Without records, you're flying blind.\n\n**What to record per trade:**\n- Date and time\n- Currency pair and direction\n- Entry price, stop loss, take profit\n- Lot size and risk amount ($)\n- Setup type (e.g. "4H pin bar at support")\n- Time frame\n- Screenshot of chart at entry\n- Result (win/loss, pips, $)\n- Notes: what went right/wrong, emotions felt\n\n**Weekly review questions:**\n- What setups performed best this week?\n- Did I follow my rules on every trade?\n- Were any losses avoidable?\n- What patterns am I seeing in my mistakes?\n- What is my current win rate and average RR?\n\n**Tools:**\n- Excel/Google Sheets (free, customizable)\n- Edgewonk (paid, analytics)\n- Myfxbook (connects to MT4, automatic)\n- TraderVue (web-based)\n\n**Minimum review frequency:** Weekly for active traders, after every 20 trades for less active traders.\n\nMost traders who quit after 6-12 months never kept a journal. Coincidence? No.` },
      { title: 'Creating a Trading Plan', duration: '25 min', content: `A trading plan is your business plan for trading. It removes emotion by pre-defining every decision.\n\n**Your trading plan must include:**\n\n**1. Trading hours**\nWhen will you trade? (e.g. London session 8:00-12:00 GMT only)\n\n**2. Markets traded**\nWhich pairs? (e.g. EUR/USD, GBP/USD, USD/JPY only)\n\n**3. Setup criteria**\nExact conditions required to enter a trade\n\n**4. Risk rules**\n- Max risk per trade: 1%\n- Max daily loss: 3%\n- Max open trades: 3\n\n**5. Entry, SL, TP rules**\nExactly how and where you enter, set stop, and set target\n\n**6. Trade management**\nWhen do you move to breakeven? When do you trail?\n\n**7. Review schedule**\nWhen do you review trades and update the plan?\n\n**The test:** Could someone else read your plan and execute it exactly as you intended? If not, it needs more detail.\n\nWrite it. Print it. Put it next to your screen. Refer to it before every single trade.\n\nA plan followed consistently, even an imperfect one, beats random trading every time.` },
      { title: 'Final Assessment', duration: '15 min', content: `Congratulations on completing Risk Management & Psychology! 🎉\n\n**Key takeaways:**\n\n✅ 70-80% of traders fail — most due to poor risk management and psychology\n✅ Always define RR before entering — minimum 1:1.5, aim for 1:2\n✅ Risk only 1-2% of account per trade — always\n✅ Position size is calculated from stop loss distance, not guessed\n✅ Drawdown recovery gets exponentially harder — protect capital above all\n✅ Losses are inevitable — your job is to execute your plan, not win every trade\n✅ After any stop out, step away for 30 minutes — no revenge trading\n✅ Keep a trading journal — reviewed weekly\n✅ A written trading plan is non-negotiable\n\n**Your next steps:**\n1. Write your complete trading plan today\n2. Set up a trading journal (at minimum a Google Sheet)\n3. Define your daily/weekly loss limits and commit to them\n4. Proceed to PAMM Account Investing or Price Action Trading\n\nYou now have the mental and risk framework of a professional trader. Now execute with discipline. 🚀` },
    ],
  },
  {
    id: 4,
    title: 'PAMM Account Investing',
    level: 'Advanced',
    lessons: 8,
    duration: '2.5 hrs',
    description: 'How to evaluate, invest in, and monitor PAMM managed accounts.',
    overview: 'Learn how to invest in professionally managed PAMM accounts. Understand how to evaluate manager performance, read drawdown statistics, and diversify across multiple managers.',
    curriculum: [
      { title: 'What is a PAMM Account?', duration: '20 min', content: `A PAMM (Percentage Allocation Management Module) account is a type of managed forex account where a professional trader (the manager) trades a pooled fund on behalf of multiple investors.\n\n**How it works:**\n1. A professional trader opens a PAMM account\n2. Investors allocate capital to the manager's account\n3. The manager trades the combined pool\n4. Profits and losses are distributed proportionally to each investor's share\n5. The manager earns a performance fee (typically 20-30% of profits)\n\n**Example:**\n- Manager's own capital: $10,000 (10%)\n- Investor A: $40,000 (40%)\n- Investor B: $50,000 (50%)\n- Total pool: $100,000\n\nIf the manager generates 10% profit ($10,000):\n- Manager receives: $1,000 (their 10% share) + performance fee\n- Investor A receives: $4,000 (40% of profit) − performance fee share\n- Investor B receives: $5,000 (50% of profit) − performance fee share\n\n**Benefits for investors:**\n- Access to professional trading without trading yourself\n- Full transparency of trading history\n- Can withdraw at defined periods\n- Manager's own capital is at risk (alignment of interests)` },
      { title: 'How PAMM Profit Sharing Works', duration: '18 min', content: `Understanding the fee structure is critical before investing in any PAMM account.\n\n**Performance fee:**\nThe most common fee in PAMM accounts. The manager earns a percentage of profits only — typically 20-30%.\n\n**High Water Mark:**\nMost reputable PAMM accounts use a high water mark. The manager only earns performance fees on NEW profits above the previous peak. This protects investors from paying fees twice on the same profit.\n\n**Example with 20% performance fee:**\n- Month 1: +15% profit → Manager earns 20% of 15% = 3% (paid by reducing your return)\n- Month 2: −8% loss → No fee\n- Month 3: +5% profit → Price recovers to previous high water mark, no fee on recovery\n- Month 4: +10% new high → Manager earns 20% of the new 10% = 2%\n\n**Management fee:**\nSome managers charge a flat annual management fee (0.5-2%) regardless of performance. Prefer managers with performance-only fees.\n\n**Withdrawal terms:**\nMost PAMM accounts allow withdrawals at fixed intervals (weekly, monthly, or quarterly). Understand this before investing — your capital may be locked up for periods.\n\n**Tax:**\nPAMM profits are generally treated as investment income. Consult a tax advisor in your jurisdiction.` },
      { title: 'Evaluating a PAMM Manager', duration: '25 min', content: `Choosing the right PAMM manager is the most important decision in PAMM investing. Here's a rigorous evaluation framework:\n\n**Step 1: Track record length**\n- Minimum 12 months of live trading history\n- 24+ months is strongly preferred\n- Demo account history means nothing\n\n**Step 2: Consistency**\n- Look for steady monthly returns (5-15% monthly is realistic for skilled managers)\n- Be very skeptical of managers showing 50-100% monthly returns — unsustainable\n- Check for consistent positive months vs. large swings\n\n**Step 3: Maximum drawdown**\n- Acceptable: under 20%\n- Concerning: 20-35%\n- Avoid: over 35% drawdown\n- The drawdown tells you the worst pain investors have experienced\n\n**Step 4: Manager's own skin in the game**\n- What percentage of the pool is the manager's own capital?\n- More skin in the game = better alignment of interests\n- Minimum 10%, prefer 20%+\n\n**Step 5: Trading style transparency**\n- Can you see open trades in real time?\n- Does the manager communicate with investors?\n- Is there an explanation of their strategy?\n\n**Step 6: Broker and account verification**\n- Is the account on a regulated broker?\n- Is the track record verified by the broker (not just reported by the manager)?` },
      { title: 'Reading Performance Statistics', duration: '22 min', content: `PAMM performance statistics can be misleading if you don't know what to look for. Here's how to read them properly.\n\n**Total Return:** The cumulative gain since the account started. High total return is meaningless without context of time and risk taken.\n\n**Monthly Return:** Average monthly gain. Sustainable range: 3-15% for conservative to moderate managers.\n\n**Annualized Return:** Total return expressed as an annual rate. Allows comparison between managers with different track record lengths.\n\n**Sharpe Ratio:** Return per unit of risk. Higher is better.\n- Above 1.0: acceptable\n- Above 2.0: excellent\n- Formula: (Portfolio Return − Risk Free Rate) / Standard Deviation\n\n**Sortino Ratio:** Similar to Sharpe but only penalizes downside volatility. More relevant for traders (we only care about downside risk, not upside volatility).\n\n**Maximum Drawdown:** The largest peak-to-trough decline in account history. This is your worst-case scenario as an investor.\n\n**Recovery Factor:** Total profit / Maximum drawdown. Above 3 is good — means the account has earned 3× what it lost in its worst drawdown.\n\n**Profit Factor:** Gross winning trades / Gross losing trades. Above 1.5 is good.\n\n**Win Rate:** Percentage of profitable trades. Meaningless without knowing the average win/loss size.` },
      { title: 'Drawdown & Risk Metrics', duration: '20 min', content: `Drawdown analysis is the most important risk assessment tool for PAMM investing.\n\n**Types of drawdown to analyze:**\n\n**1. Absolute maximum drawdown:**\nThe single worst decline from peak to trough in the account's entire history. This represents your worst-case realized scenario.\n\n**2. Current drawdown:**\nIs the account currently in drawdown? If yes, by how much? Be cautious of accounts in significant current drawdown — they may be in a strategy failure.\n\n**3. Drawdown duration:**\nHow long did it take to recover from the maximum drawdown? Long recovery periods (6+ months) suggest the strategy struggled significantly.\n\n**4. Average drawdown:**\nThe average of all drawdown periods. Gives a more realistic expectation of regular losses.\n\n**Red flags in drawdown analysis:**\n- Maximum drawdown > 30%\n- Current drawdown approaching historical maximum\n- Multiple large drawdown events (not just one bad period)\n- Drawdown that increases in magnitude over time\n- Account using martingale or grid strategies (exponential risk)\n\n**Stress testing:**\nAsk yourself: "If this account loses 30% from its current level, can I handle that financially and psychologically?" If no, either invest less or don't invest at all.` },
      { title: 'Diversifying Across Managers', duration: '18 min', content: `Just as stock investors diversify across assets, PAMM investors should diversify across multiple managers.\n\n**Why diversify:**\n- Even skilled managers have losing periods\n- Different strategies perform differently in different market conditions\n- Reduces the impact of any single manager failing\n\n**Diversification framework:**\n\n**By strategy type:**\n- Trend following manager (performs well in trending markets)\n- Range trading manager (performs well in ranging markets)\n- Scalping manager (consistent small gains)\n- News trading manager (event-driven)\n\n**By currency focus:**\n- Manager specializing in EUR/USD and majors\n- Manager specializing in JPY pairs\n- Manager specializing in exotics\n\n**By risk profile:**\n- 50% in low-risk, low-return manager (3-8% monthly, <10% drawdown)\n- 30% in medium-risk manager (8-15% monthly, <20% drawdown)\n- 20% in higher-risk, higher-return manager (15-25% monthly, <30% drawdown)\n\n**Correlation check:**\nIf two managers both trade EUR/USD trend following, they'll likely lose at the same time. Look for managers with low correlation in their returns.\n\n**Minimum allocation:** Don't allocate less than 5% to any single manager — too small to matter. Don't allocate more than 40% — too concentrated.` },
      { title: 'Withdrawal Strategies', duration: '18 min', content: `A smart withdrawal strategy protects your profits while allowing your investment to compound.\n\n**Strategy 1: Fixed percentage withdrawal**\nWithdraw a fixed % each month (e.g. 50% of profits).\n- Pros: Regular income, protects profits\n- Cons: Limits compounding\n\n**Strategy 2: Full compounding**\nReinvest all profits, withdraw nothing.\n- Pros: Maximum account growth via compounding\n- Cons: All profits at risk\n- Best for: Long-term wealth building\n\n**Strategy 3: Return of capital first**\nKeep withdrawing until you've recovered your initial investment, then compound the rest.\n- Pros: Removes original capital risk quickly\n- Cons: Slower compounding early on\n\n**Strategy 4: Milestone withdrawals**\nWithdraw when account hits specific milestones (e.g. every time account doubles).\n\n**Compounding example (10% monthly, no withdrawal):**\n- Month 1: $10,000 → $11,000\n- Month 6: $17,716\n- Month 12: $31,384\n- Month 24: $98,497\n\n**Rebalancing:**\nIf one manager grows significantly larger than your target allocation, withdraw and redistribute to maintain your diversification ratios.\n\n**Tax timing:** Consider tax implications of withdrawal timing — withdrawing at year-end vs. start of new tax year may have different implications.` },
      { title: 'Final Assessment', duration: '15 min', content: `Congratulations on completing PAMM Account Investing! 🎉\n\n**Key takeaways:**\n\n✅ PAMM = professional trader manages pooled capital, profits shared proportionally\n✅ Require minimum 12 months live track record before investing\n✅ Maximum drawdown should be under 20% for low-risk allocation\n✅ Performance fee with high water mark is the fairest fee structure\n✅ Sharpe Ratio > 1.0 and Recovery Factor > 3 indicate quality management\n✅ Diversify across 3-5 managers with different strategies\n✅ Never allocate more than 40% to a single manager\n✅ Have a written withdrawal strategy before investing\n✅ Only invest on regulated broker platforms with verified track records\n\n**Your next steps:**\n1. Identify 5 potential PAMM managers on your broker's platform\n2. Evaluate each using the framework from this course\n3. Start with a small allocation (5-10% of available capital) to your top 2-3 managers\n4. Review performance monthly\n\nPAMM investing is passive income done right — when you choose wisely. 🚀` },
    ],
  },
  {
    id: 5,
    title: 'Price Action Trading',
    level: 'Advanced',
    lessons: 15,
    duration: '6 hrs',
    description: 'Trade without indicators using raw price structure and market flow.',
    overview: 'Strip away indicators and learn to read the market through pure price action. Master swing highs and lows, order blocks, fair value gaps, and institutional trading concepts.',
    curriculum: [
      { title: 'Introduction to Price Action', duration: '20 min', content: `Price action trading is the practice of making trading decisions based solely on a security's price movements — without the use of lagging indicators.\n\n**Core philosophy:**\nAll information about the market is contained in the price. Volume, sentiment, fundamentals — all of it is reflected in how price moves. Therefore, studying price directly is the most accurate form of market analysis.\n\n**Why price action works:**\n- No lag (unlike indicators which are derived from past prices)\n- Works on all time frames and all markets\n- Used by institutional traders and hedge funds\n- Clean charts reduce noise and cognitive load\n\n**What you need:**\n- A clean candlestick chart\n- Understanding of market structure\n- Knowledge of key patterns\n- Patience to wait for high-probability setups\n\n**What you don't need:**\n- RSI, MACD, Stochastic, or any oscillators\n- Dozens of indicators cluttering your chart\n- Complex automated systems\n\n**The learning curve:**\nPrice action takes longer to master than indicator-based trading. It requires developing chart-reading intuition through screen time. Expect 3-6 months of consistent practice before it clicks.` },
      { title: 'Market Structure: Highs & Lows', duration: '25 min', content: `Market structure is the foundation of all price action analysis. Understanding it tells you the trend, potential reversal points, and where to place trades.\n\n**Swing High:** A candle with a higher high than the candles on both sides\n**Swing Low:** A candle with a lower low than the candles on both sides\n\n**Uptrend (Bullish structure):**\nSeries of Higher Highs (HH) and Higher Lows (HL)\n- Each swing high is higher than the previous\n- Each swing low is higher than the previous\n- Trade: buy pullbacks to swing lows\n\n**Downtrend (Bearish structure):**\nSeries of Lower Highs (LH) and Lower Lows (LL)\n- Each swing high is lower than the previous\n- Each swing low is lower than the previous\n- Trade: sell rallies to swing highs\n\n**Range (Consolidation):**\nPrice oscillating between a fixed high and low without making new highs or lows\n- Trade: buy at range bottom, sell at range top\n- Breakout of range = new trend beginning\n\n**Key rule:**\nAlways trade in the direction of the higher time frame structure. If the Daily chart shows Higher Highs and Higher Lows, only look for buy setups on the 4H and 1H.` },
      { title: 'Breaks of Structure', duration: '22 min', content: `A Break of Structure (BOS) occurs when price moves beyond a significant swing high or low, signaling trend continuation.\n\n**Bullish BOS:**\nIn an uptrend, when price breaks above the most recent swing high = confirmation the uptrend is continuing.\n- After a BOS, look for pullbacks to enter in the direction of the break\n\n**Bearish BOS:**\nIn a downtrend, when price breaks below the most recent swing low = confirmation the downtrend is continuing.\n\n**Trading BOS:**\n1. Identify the overall trend structure\n2. Wait for a pullback/consolidation\n3. Enter when price breaks the consolidation high (bullish) or low (bearish)\n4. Stop: below the pullback low (bullish) or above the pullback high (bearish)\n5. Target: next key level or measured move\n\n**Failed BOS (False Break):**\nSometimes price briefly breaks a level then reverses — this is a liquidity sweep. Price takes out stops above resistance, then falls sharply. Recognizing false breaks is an advanced skill that comes with screen time.\n\n**Difference from regular breakout:**\nBOS in the context of market structure carries more weight than a simple horizontal level breakout, because it signals the trend is actively continuing.` },
      { title: 'Change of Character (CHOCH)', duration: '22 min', content: `Change of Character (CHOCH) is a price action concept that signals a potential trend reversal — the shift from bullish to bearish structure or vice versa.\n\n**Identifying CHOCH:**\n\nIn an uptrend (HH/HL):\n- Price forms a new Higher High\n- Instead of forming a Higher Low (as expected), price drops below the previous Higher Low\n- This lower low CHANGES the character of the move from bullish to potentially bearish\n- This is a CHOCH\n\nIn a downtrend (LH/LL):\n- Price forms a new Lower Low\n- Instead of forming a Lower High, price rallies above the previous Lower High\n- This higher high is a CHOCH — potential reversal\n\n**Why CHOCH matters:**\nIt's the earliest warning that the trend may be reversing. It comes before the full confirmation of a new downtrend (which requires both a LH and LL).\n\n**Trading CHOCH:**\n- CHOCH is a warning, not a confirmed reversal signal\n- Wait for additional confirmation (order block, Fibonacci level, bearish structure on lower TF)\n- Aggressive traders enter on CHOCH; conservative traders wait for full BOS in new direction\n\n**Combining BOS and CHOCH:**\nBOS = trend continuation signal\nCHOCH = trend reversal signal\nTogether, they define the market narrative at any moment.` },
      { title: 'Order Blocks', duration: '28 min', content: `Order blocks are areas on the chart where large institutional orders were placed, causing significant price moves. Price often returns to these levels for a reaction.\n\n**What creates an order block:**\nWhen an institution (bank, hedge fund) needs to fill a large order, they can't do it all at once without moving the market. They accumulate/distribute over time, leaving a "footprint" in the form of an order block.\n\n**Identifying a Bullish Order Block:**\n1. Find a significant bullish move (impulsive move up)\n2. Look at the last bearish candle before the impulsive move began\n3. That bearish candle's range (body, not wick) = the bullish order block\n4. When price returns to this zone, expect buying pressure\n\n**Identifying a Bearish Order Block:**\n1. Find a significant bearish move (impulsive move down)\n2. Look at the last bullish candle before the move began\n3. That bullish candle's range = the bearish order block\n4. When price returns to this zone, expect selling pressure\n\n**Key characteristics of strong order blocks:**\n- Preceded by a large impulsive move\n- Has not been revisited since the original move (untested)\n- Located at a higher time frame key level\n- Aligns with Fibonacci retracement levels\n\n**Entry on an order block:**\nWait for price to enter the order block zone, then look for a bearish or bullish confirmation candle within the zone before entering.` },
      { title: 'Fair Value Gaps (FVG)', duration: '25 min', content: `A Fair Value Gap (FVG), also called an imbalance, is a 3-candle pattern where the wicks of the first and third candle do not overlap, leaving a "gap" in price that was traded only one way.\n\n**Bullish FVG:**\n- Candle 1: bearish candle\n- Candle 2: strong bullish candle (the gap candle)\n- Candle 3: bullish candle\n- Gap = between the HIGH of candle 1 and the LOW of candle 3\n- This zone was not traded in both directions — price moved through it too quickly\n\n**Bearish FVG:**\n- Candle 1: bullish candle\n- Candle 2: strong bearish candle\n- Candle 3: bearish candle\n- Gap = between the LOW of candle 1 and the HIGH of candle 3\n\n**Why price returns to FVGs:**\nMarkets tend toward efficiency. Imbalanced areas attract price back to "fill" the gap — re-test the zone where price moved too quickly in one direction.\n\n**Trading FVGs:**\n- In an uptrend: wait for price to pull back into a bullish FVG → buy\n- In a downtrend: wait for price to rally into a bearish FVG → sell\n- Combine with order blocks for highest probability\n- Stop loss: below the FVG\n- Target: next structural high (bullish) or low (bearish)\n\n**50% of FVG:** Price often reacts at the midpoint (50%) of the FVG before reaching the full gap boundary.` },
      { title: 'Liquidity Zones', duration: '25 min', content: `Liquidity is where stop losses and pending orders cluster. Institutions need liquidity to fill large orders — so price is driven to these zones to enable their fills.\n\n**Where liquidity pools form:**\n- Above swing highs (buy stop orders, retail breakout traders)\n- Below swing lows (sell stop orders, retail traders' stop losses)\n- Around equal highs/lows (obvious levels attract stop orders)\n- Round numbers (1.1000, 1.0800, 150.00)\n- Previous day/week/month highs and lows\n\n**Liquidity sweep / stop hunt:**\nPrice briefly moves beyond a liquidity zone (taking out stops), then sharply reverses in the opposite direction. This is NOT a random accident — it's institutions collecting the liquidity they need.\n\n**Identifying a liquidity sweep:**\n1. Price approaches a key swing high with obvious stops above it\n2. Price spikes above the high, taking stops out\n3. Price sharply reverses and closes below the high\n4. The reversal candle often looks like a large pin bar or engulfing\n\n**Trading liquidity sweeps:**\n- Wait for the sweep of a key level (price takes out the obvious stops)\n- Look for a reversal confirmation candle\n- Enter in the direction of the reversal\n- Stop: beyond the sweep high/low\n- Target: opposite liquidity zone\n\nThis is one of the highest-probability setups in price action trading once you can reliably identify it.` },
      { title: 'Smart Money Concepts', duration: '30 min', content: `Smart Money Concepts (SMC) is a framework for understanding how institutional traders (banks, funds) operate and how to trade alongside them.\n\n**Core premise:**\nThe forex market is primarily driven by institutional participants with massive capital. Retail traders are essentially noise. By understanding institutional behavior, retail traders can position themselves advantageously.\n\n**Key SMC concepts:**\n\n**Premium vs Discount zones:**\n- Discount zone: below the 50% of a swing = good area to buy\n- Premium zone: above the 50% of a swing = good area to sell\n- Institutions buy at discount, sell at premium\n\n**Inducement:**\nInstitutions create false signals to induce retail traders into losing positions, then take the opposite side. Example: a "breakout" above resistance that fails immediately — retail traders bought the breakout, institutions sold into them.\n\n**Institutional candles:**\nLarge momentum candles that leave FVGs and order blocks — signatures of institutional activity.\n\n**The SMC trade sequence:**\n1. Identify higher TF trend\n2. Wait for liquidity sweep in counter-trend direction\n3. Look for CHOCH on lower TF\n4. Find order block or FVG in the new direction\n5. Enter at the OB/FVG with stop beyond the sweep\n6. Target: next liquidity pool or key high/low\n\nSMC is a complete trading framework. It takes significant screen time to master but provides a coherent explanation for price behavior.` },
      { title: 'Session Timing for Entries', duration: '20 min', content: `In price action trading, timing your entries to coincide with active market sessions dramatically improves results.\n\n**Why sessions matter:**\nInstitutional orders are placed at the start of trading sessions. The highest-probability price action setups occur during session opens when volume and volatility are highest.\n\n**Asian Session (00:00 - 09:00 GMT):**\n- Low volatility, often ranges form\n- Sets up liquidity pools above and below range highs/lows\n- These pools are swept in the London session\n- Best: identify the Asian range and anticipate a sweep at London open\n\n**London Open (08:00 - 10:00 GMT):**\n- Highest probability time for price action setups\n- Often sweeps Asian session highs or lows (liquidity sweep)\n- Major moves for the day often begin here\n- Best pairs: EUR/USD, GBP/USD, EUR/GBP\n\n**New York Open (13:00 - 15:00 GMT):**\n- Second highest probability window\n- Often confirms or reverses the London move\n- Highest volatility: London + NY overlap (13:00-17:00 GMT)\n\n**Killzones (optimal entry windows):**\n- London Killzone: 08:00 - 10:00 GMT\n- NY Killzone: 13:00 - 15:00 GMT\n- Trade setups that form in these windows carry more institutional weight.` },
      { title: 'Confluence Trading', duration: '25 min', content: `Confluence means multiple independent factors aligning to support the same trade idea. High-confluence setups have the highest probability of success.\n\n**Confluence factors in price action:**\n1. Higher time frame structure (daily uptrend)\n2. Fibonacci retracement level (61.8%)\n3. Order block or FVG present at the same level\n4. Session timing (London killzone)\n5. Liquidity sweep (stops taken out below)\n6. Confirmation candle (bullish pin bar or engulfing)\n\n**Scoring system:**\nAssign 1 point per confluence factor. Only take trades with 3+ points.\n- 3 factors: valid trade\n- 4-5 factors: strong trade, can use slightly larger position\n- 6+ factors: maximum conviction, rare but highest probability\n\n**Example high-confluence buy setup (EUR/USD):**\n☑ Daily trend bullish (HH/HL structure)\n☑ Price at 61.8% Fibonacci retracement of last swing\n☑ Bullish order block from 4H at same level\n☑ London killzone timing\n☑ Liquidity sweep below the swing low (Asian session low taken out)\n☑ Bullish engulfing candle on 1H\nScore: 6/6 — maximum conviction trade\n\n**Common mistake:** Taking trades with only 1-2 confluence factors. Low confluence = gambling. Patience to wait for 3+ factors = professional trading.` },
      { title: 'Trade Management with Price Action', duration: '22 min', content: `Price action doesn't just help with entries — it provides guidance for managing trades once they're open.\n\n**Initial stop placement:**\nPlace stop beyond the last swing low (long) or swing high (short) — beyond the structure that invalidates your trade idea.\n\n**Moving to breakeven:**\nMove stop to entry price once:\n- Price has moved 1:1 RR in your favor, OR\n- A new swing low forms above your entry (for longs)\nThis gives you a "free trade" — worst outcome is breakeven.\n\n**Trailing the stop:**\n1. As new swing lows form (in an uptrend), move stop to below each new swing low\n2. This trails price action structurally — you exit when the structure breaks\n3. Allows you to stay in strong trending moves without an arbitrary exit\n\n**Partial exits:**\n- Take 50% off at first key resistance or 1:1 RR\n- Move stop to breakeven\n- Let remaining 50% run with a trailed stop\n- This locks in some profit while allowing the trade to develop\n\n**When to cut a trade early:**\n- A strong bearish momentum candle into your position (structure change)\n- A CHOCH on a lower time frame against your trade\n- Price fails to break a key level it should break if the trade thesis is valid\n\n**When NOT to cut early:**\n- A small pullback within your stop range (normal price fluctuation)\n- The trade is in drawdown but structure remains intact` },
      { title: 'Scalping vs Swing Trading', duration: '22 min', content: `Price action can be applied to any time frame — but scalping and swing trading require different approaches and mindsets.\n\n**Scalping (1M - 15M charts):**\n- Hold time: seconds to minutes\n- Target: 5-20 pips\n- Requires fastest execution and tightest spreads\n- Best pairs: EUR/USD, USD/JPY (tightest spreads)\n- Best time: London and NY opens\n- Requires intense focus and quick decision-making\n- Suitable for: full-time traders, people who enjoy fast-paced trading\n\n**Swing Trading (4H - Daily charts):**\n- Hold time: hours to days\n- Target: 50-300 pips\n- Forgiving on execution — spread impact minimal\n- Works on all major pairs\n- 1-3 trades per week maximum\n- Suitable for: part-time traders, people with full-time jobs\n\n**Day Trading (15M - 1H charts):**\n- Middle ground between scalping and swing\n- Hold time: 1-8 hours\n- No overnight positions\n\n**Recommendation for new price action traders:**\nStart with swing trading on the 4H chart. It gives you more time to analyze and react, with bigger targets that absorb spread and commission easily. Master 4H first, then move to lower time frames if desired.` },
      { title: 'Live Trade Examples', duration: '35 min', content: `Let's walk through complete price action trade examples using the concepts from this course.\n\n**Trade 1: GBP/USD Long (SMC Setup)**\n- Daily: HH/HL uptrend intact\n- 4H: Price pulled back, swept liquidity below previous HL (Asian session low)\n- 1H: CHOCH bullish — formed higher high after liquidity sweep\n- 1H: Bullish order block identified at 1.2620-1.2635\n- Entry: 1.2628 (OB midpoint), Stop: 1.2605 (below sweep), Target: 1.2720\n- RR: 3.8:1\n- Confluence: Trend ✓, Liquidity sweep ✓, CHOCH ✓, Order block ✓, Session timing ✓ = 5/5\n\n**Trade 2: EUR/USD Short (FVG + Resistance)**\n- Daily: LH/LL downtrend\n- 4H: Rally into bearish FVG at 1.0880-1.0895\n- 1H: Bearish pin bar at top of FVG\n- Entry: 1.0882, Stop: 1.0902 (above FVG), Target: 1.0800\n- RR: 4.1:1\n- Confluence: Trend ✓, FVG ✓, Confirmation candle ✓, Premium zone ✓ = 4/4\n\n**Trade 3: USD/JPY Long (Asian Range Sweep + London Open)**\n- Asian session created range: 149.20 - 149.60\n- At 08:05 GMT (London open): Price swept below 149.20 (liquidity grab)\n- Bullish engulfing on 15M reclaimed 149.20\n- Entry: 149.25, Stop: 149.10 (below sweep), Target: 149.75\n- RR: 3.3:1\n- Classic Asian range sweep at London open setup` },
      { title: 'Building Your PA Strategy', duration: '28 min', content: `Now let's build a complete, rule-based price action strategy you can trade starting tomorrow.\n\n**The 3-Step PA Strategy:**\n\n**Step 1: Bias (Daily chart - 5 min)**\n- Is the daily chart in HH/HL uptrend or LH/LL downtrend?\n- Where are the key levels (significant swing highs and lows)?\n- Bull bias = only look for longs on lower TF\n\n**Step 2: Setup (4H chart - 10 min)**\n- Has price pulled back to a key structure level?\n- Is there an order block or FVG at the pullback level?\n- Has there been a liquidity sweep at the pullback level?\n\n**Step 3: Entry (1H chart - 5 min, during London or NY killzone)**\n- Does price show a bullish CHOCH or reversal pattern at the 4H level?\n- Is there a confirmation candle (pin bar, engulfing, or strong close)?\n- If yes to all: enter with stop below the confirmation candle low\n\n**Full entry checklist:**\n☐ Daily trend direction identified\n☐ 4H pullback to structure (OB, FVG, or S/R level)\n☐ Liquidity sweep present\n☐ 1H CHOCH or reversal signal\n☐ London or NY killzone timing\n☐ Stop: below sweep low (long) or above sweep high (short)\n☐ Target: next daily structural level\n☐ RR: minimum 1:2\n\n**Starting out:** Focus on EUR/USD and GBP/USD. Trade the daily and 4H only for the first 3 months. Add complexity only after mastering the basics.` },
      { title: 'Final Assessment', duration: '15 min', content: `Congratulations on completing Price Action Trading! 🎉\n\n**Key takeaways:**\n\n✅ Price action = trading from raw price, no indicators needed\n✅ Market structure (HH/HL or LH/LL) defines the trend\n✅ BOS = continuation; CHOCH = potential reversal\n✅ Order blocks = institutional footprints where price reacts\n✅ FVGs = imbalances price returns to fill\n✅ Liquidity sweeps = institutions hunting stops before the real move\n✅ Trade only in killzones (London 08-10 GMT, NY 13-15 GMT)\n✅ Require 3+ confluence factors before entering\n✅ Manage trades structurally — trail stops to swing lows/highs\n✅ Start with 4H swing trading, master it before going to lower TFs\n\n**Your next steps:**\n1. Mark your charts daily — identify structure, OBs, FVGs\n2. Only take setups in killzones for 30 days\n3. Track every trade in your journal with confluence score\n4. Review weekly — which confluence combinations performed best?\n5. Proceed to Automated Trading & EAs if you want to automate your PA rules\n\nYou now have one of the most powerful trading frameworks used by professional traders worldwide. The edge is in your execution. 🚀` },
    ],
  },
  {
    id: 6,
    title: 'Automated Trading & EAs',
    level: 'Advanced',
    lessons: 14,
    duration: '5 hrs',
    description: 'Build and backtest Expert Advisors on MetaTrader 4/5.',
    overview: 'Learn to automate your trading strategies using MetaTrader Expert Advisors. From basic MQL4/5 scripting to backtesting, optimization, and deploying on a VPS.',
    curriculum: [
      { title: 'Introduction to Automated Trading', duration: '20 min', content: `Automated trading (also called algorithmic or systematic trading) uses computer programs to execute trades based on pre-defined rules — removing human emotion from the equation.\n\n**Benefits of automated trading:**\n- No emotion — executes rules mechanically every time\n- Backtestable — test strategy on years of historical data in minutes\n- Faster execution than manual trading\n- Can monitor multiple pairs simultaneously\n- Trades while you sleep\n\n**Limitations:**\n- Only as good as the rules you program\n- Can fail in unusual market conditions\n- Requires monitoring (technology failures, broker issues)\n- Programming skills required\n\n**Types of automated systems:**\n- **Expert Advisors (EAs):** Programs running inside MetaTrader 4/5\n- **Python bots:** Custom scripts using broker APIs\n- **Copy trading platforms:** Automatically copy another trader's signals\n\n**This course focuses on EAs** — the most accessible form of automated trading for forex, with a huge community and built-in backtesting tools.\n\n**Who should automate:**\n- Traders with a consistently profitable manual strategy\n- People who want to remove emotional interference\n- Traders who want to trade more pairs/time frames simultaneously\n\n**Rule:** Never automate a strategy you haven't proven profitable manually first.` },
      { title: 'MetaTrader 4 vs MetaTrader 5', duration: '18 min', content: `MetaTrader 4 (MT4) and MetaTrader 5 (MT5) are the two most popular trading platforms for retail forex traders. Both support Expert Advisors but have important differences.\n\n**MetaTrader 4 (MT4):**\n- Released: 2005\n- Still the most widely used platform in retail forex\n- Older, more limited (only forex and CFDs)\n- MQL4 language (older, simpler)\n- Huge library of existing EAs and indicators\n- Most brokers support it\n- Recommended for: beginners to automated trading\n\n**MetaTrader 5 (MT5):**\n- Released: 2010\n- Supports forex, stocks, futures, options\n- More advanced backtesting (multi-currency, real tick data)\n- MQL5 language (more modern, similar to C++)\n- Faster backtesting and optimization\n- Growing library of EAs\n- Recommended for: more serious automation, multi-asset trading\n\n**Which to choose:**\n- If your broker only offers MT4: use MT4\n- If you have a choice: MT5 for new projects\n- If you find an EA you want to use: check which platform it's built for\n\n**MQL4 vs MQL5:**\nBoth are C++-like languages. MQL5 is more powerful but has a steeper learning curve. MQL4 code cannot run on MT5 directly (requires conversion).` },
      { title: 'MQL4/5 Basics', duration: '30 min', content: `MQL (MetaQuotes Language) is the programming language used to create EAs, indicators, and scripts in MetaTrader.\n\n**Basic structure of an EA:**\n\n\`\`\`mql4\n// Initialization function — runs once on startup\nint OnInit() {\n   return(INIT_SUCCEEDED);\n}\n\n// Deinitialization — runs when EA is removed\nvoid OnDeinit(const int reason) {\n}\n\n// Main function — runs on every new tick (price change)\nvoid OnTick() {\n   // Your trading logic here\n}\n\`\`\`\n\n**Key built-in variables:**\n- \`Ask\` — current ask price\n- \`Bid\` — current bid price\n- \`Symbol()\` — current pair (e.g. "EURUSD")\n- \`Period()\` — current chart time frame\n\n**Key functions:**\n- \`OrderSend()\` — place a trade\n- \`OrderClose()\` — close a trade\n- \`iMA()\` — get moving average value\n- \`iRSI()\` — get RSI value\n- \`MarketInfo()\` — get market information\n\n**Variable types:**\n- \`int\` — whole numbers\n- \`double\` — decimal numbers (prices, lots)\n- \`string\` — text\n- \`bool\` — true/false\n- \`datetime\` — date and time\n\n**Getting started:**\nOpen MetaEditor (F4 in MT4/MT5) → New → Expert Advisor → follow the wizard. MetaEditor has autocomplete and documentation built in.` },
      { title: 'Your First EA: Structure & Logic', duration: '35 min', content: `Let's build a simple but complete EA from scratch — a Moving Average crossover system.\n\n**Strategy:**\n- Buy when Fast MA (10 EMA) crosses above Slow MA (50 EMA)\n- Sell when Fast MA crosses below Slow MA\n- Fixed 30 pip stop loss, 60 pip take profit (1:2 RR)\n\n\`\`\`mql4\n// Input parameters\nextern int FastMA_Period = 10;\nextern int SlowMA_Period = 50;\nextern double LotSize = 0.1;\nextern int StopLoss = 30;\nextern int TakeProfit = 60;\n\nvoid OnTick() {\n   // Only trade on new bar (not every tick)\n   if (Volume[0] > 1) return;\n   \n   // Get MA values\n   double fastMA_current = iMA(NULL, 0, FastMA_Period, 0, MODE_EMA, PRICE_CLOSE, 0);\n   double fastMA_previous = iMA(NULL, 0, FastMA_Period, 0, MODE_EMA, PRICE_CLOSE, 1);\n   double slowMA_current = iMA(NULL, 0, SlowMA_Period, 0, MODE_EMA, PRICE_CLOSE, 0);\n   double slowMA_previous = iMA(NULL, 0, SlowMA_Period, 0, MODE_EMA, PRICE_CLOSE, 1);\n   \n   // Buy condition: Fast MA crosses above Slow MA\n   bool buySignal = (fastMA_previous < slowMA_previous) && \n                    (fastMA_current > slowMA_current);\n   \n   // Sell condition: Fast MA crosses below Slow MA\n   bool sellSignal = (fastMA_previous > slowMA_previous) && \n                     (fastMA_current < slowMA_current);\n   \n   if (buySignal && OrdersTotal() == 0) {\n      OrderSend(Symbol(), OP_BUY, LotSize, Ask, 3,\n                Ask - StopLoss * Point * 10,\n                Ask + TakeProfit * Point * 10,\n                "MA Cross EA", 0, 0, clrGreen);\n   }\n   \n   if (sellSignal && OrdersTotal() == 0) {\n      OrderSend(Symbol(), OP_SELL, LotSize, Bid, 3,\n                Bid + StopLoss * Point * 10,\n                Bid - TakeProfit * Point * 10,\n                "MA Cross EA", 0, 0, clrRed);\n   }\n}\n\`\`\`\n\nThis is a complete, working EA. Compile it in MetaEditor (F7) and run it on a demo chart to test.` },
      { title: 'Entry & Exit Conditions in Code', duration: '30 min', content: `Converting your manual trading rules into precise code requires careful thinking about exactly what conditions trigger entries and exits.\n\n**Common entry conditions and their code equivalents:**\n\n**Price above/below MA:**\n\`\`\`mql4\ndouble ma200 = iMA(NULL, 0, 200, 0, MODE_EMA, PRICE_CLOSE, 0);\nbool aboveMA = (Close[0] > ma200); // Bullish condition\n\`\`\`\n\n**RSI oversold:**\n\`\`\`mql4\ndouble rsi = iRSI(NULL, 0, 14, PRICE_CLOSE, 0);\nbool oversold = (rsi < 30);\n\`\`\`\n\n**Candle pattern (bullish engulfing):**\n\`\`\`mql4\nbool bullishEngulfing = (Close[1] < Open[1]) &&  // Previous candle bearish\n                        (Close[0] > Open[0]) &&  // Current candle bullish\n                        (Open[0] < Close[1]) &&  // Current opens below prev close\n                        (Close[0] > Open[1]);    // Current closes above prev open\n\`\`\`\n\n**Support level test:**\n\`\`\`mql4\ndouble supportLevel = 1.0800;\nbool atSupport = (Low[0] <= supportLevel + 0.0010 && \n                  Low[0] >= supportLevel - 0.0010);\n\`\`\`\n\n**Time filter (London session only):**\n\`\`\`mql4\ndatetime currentTime = TimeCurrent();\nint hour = TimeHour(currentTime);\nbool inSession = (hour >= 8 && hour <= 16);\n\`\`\`\n\n**Key principle:** Define every condition exactly. What is "at support" — within 5 pips? 10 pips? Be specific. Ambiguity in manual trading becomes bugs in code.` },
      { title: 'Risk Management in Code', duration: '25 min', content: `Automated risk management is more reliable than manual — it executes perfectly every time without emotion.\n\n**Dynamic position sizing:**\n\`\`\`mql4\ndouble CalculateLotSize(double riskPercent, double stopLossPips) {\n   double accountBalance = AccountBalance();\n   double riskAmount = accountBalance * riskPercent / 100.0;\n   \n   double pipValue = MarketInfo(Symbol(), MODE_TICKVALUE);\n   if (Point == 0.00001 || Point == 0.001) // 5-digit broker\n      pipValue *= 10;\n   \n   double lotSize = riskAmount / (stopLossPips * pipValue);\n   \n   // Round to nearest 0.01\n   lotSize = MathFloor(lotSize / 0.01) * 0.01;\n   \n   // Apply broker limits\n   double minLot = MarketInfo(Symbol(), MODE_MINLOT);\n   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);\n   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));\n   \n   return lotSize;\n}\n\`\`\`\n\n**Daily loss limit:**\n\`\`\`mql4\ndouble startOfDayBalance = 0;\n\nvoid OnTick() {\n   if (startOfDayBalance == 0) startOfDayBalance = AccountBalance();\n   \n   double drawdown = (startOfDayBalance - AccountEquity()) / startOfDayBalance * 100;\n   if (drawdown >= 3.0) { // 3% daily loss limit\n      // Close all trades and stop trading\n      CloseAllTrades();\n      return;\n   }\n   // ... rest of EA logic\n}\n\`\`\`\n\n**Max open trades:**\n\`\`\`mql4\nif (OrdersTotal() >= 3) return; // Max 3 concurrent trades\n\`\`\`\n\nGood risk management code is often more important than the entry logic.` },
      { title: 'Backtesting Strategies', duration: '28 min', content: `Backtesting allows you to test your EA against years of historical data in minutes.\n\n**Running a backtest in MT4:**\n1. Press Ctrl+R (or View → Strategy Tester)\n2. Select your EA from the Expert Advisor dropdown\n3. Select the pair and time frame\n4. Set the date range (minimum 1 year, prefer 3-5 years)\n5. Select "Every tick" for most accurate results\n6. Click Start\n\n**Understanding the backtest report:**\n\n- **Net Profit:** Total profit over the test period\n- **Profit Factor:** Gross profit / Gross loss (target > 1.5)\n- **Max Drawdown:** Largest peak-to-trough decline\n- **Total Trades:** Number of trades (need 100+ for statistical significance)\n- **Win Rate:** % of profitable trades\n- **Average trade profit:** Net profit / Total trades\n\n**Quality of backtest data:**\nMT4's default tick data is modeled (90% quality). For more accurate testing:\n- Download broker's tick data\n- Use Dukascopy free tick data\n- Aim for 99% modeling quality\n\n**Interpreting results:**\nA "good" backtest:\n- Profit factor > 1.5\n- Max drawdown < 20%\n- 200+ trades\n- Consistent performance across different years (not just one good year)\n- Similar performance on out-of-sample data` },
      { title: 'Optimizing Parameters', duration: '25 min', content: `Optimization finds the best parameters for your EA (e.g. what MA period works best). MT4/5 has a built-in optimizer.\n\n**Running optimization in MT4:**\n1. In Strategy Tester, check "Optimization"\n2. Click "Expert properties"\n3. Check the parameters you want to optimize\n4. Set the range and step (e.g. MA period: min 5, max 50, step 5)\n5. Set optimization criterion (maximize profit factor or balance)\n6. Click Start\n\n**Reading optimization results:**\n- Sort by your optimization criterion\n- Look for a cluster of good results around similar parameters (robustness)\n- Avoid single "spike" results (likely curve fitting)\n\n**Example — optimizing MA crossover:**\nTest Fast MA: 5-20 (step 1) vs Slow MA: 30-100 (step 5)\nIf results around Fast=10, Slow=50 all perform well → robust parameters\nIf only Fast=12, Slow=67 performs well → likely curve fit, don't use\n\n**How to avoid over-optimization:**\n1. Split data: optimize on 70% of data, test on remaining 30%\n2. Use wide parameter ranges in search\n3. Choose parameters in the middle of a performance cluster\n4. Verify results hold on multiple pairs\n5. Forward test on demo account before live trading` },
      { title: 'Avoiding Curve Fitting', duration: '22 min', content: `Curve fitting (also called over-optimization or overfitting) is the biggest danger in automated trading. It's when your EA is optimized so precisely for historical data that it fails in live markets.\n\n**How curve fitting happens:**\n- You run optimization on EUR/USD 2020-2024\n- You find parameters that produce 300% profit on those exact years\n- You go live in 2025 — the EA loses money immediately\n- The parameters worked for that specific historical period but not the real market\n\n**Warning signs of a curve-fit EA:**\n- Perfect equity curve (too smooth, no significant drawdowns)\n- Dozens of parameters, all highly specific values\n- Only works on one pair and one time frame\n- Performance degrades significantly outside the optimization period\n- Very high backtest profit but poor forward test results\n\n**How to build robust EAs:**\n1. **Fewer parameters:** Each additional parameter increases overfitting risk\n2. **Walk-forward testing:** Optimize on period 1, test on period 2, optimize again, test on period 3 — repeat\n3. **Multiple market tests:** Test on EUR/USD, GBP/USD, USD/JPY — a robust strategy works on multiple pairs\n4. **Monte Carlo simulation:** Randomly alter trade order and size — a robust strategy performs well under many scenarios\n5. **Simplicity:** Simple strategies (2-3 rules) generalize better than complex ones\n\n**Golden rule:** If your EA only works after extensive parameter optimization on one specific dataset, it's curve fit. Start over with a simpler concept.` },
      { title: 'Forward Testing', duration: '20 min', content: `Forward testing (also called paper trading or demo testing) is running your EA on a demo account in real-time market conditions after backtesting is complete.\n\n**Why forward testing matters:**\nBacktesting uses historical data with simplified assumptions. Real markets have:\n- Slippage (different execution price than expected)\n- Variable spreads (especially during news events)\n- Broker-specific latency\n- Requotes (rare but possible)\n\nForward testing reveals these real-world factors.\n\n**Forward testing protocol:**\n1. Complete backtesting with satisfactory results (PF > 1.5, DD < 20%)\n2. Run EA on demo account for minimum 3 months\n3. Use the same lot size you intend to use live\n4. Record every trade: entry, SL, TP, outcome\n5. Compare with backtest results — are they similar?\n\n**What to look for:**\n- Is the win rate close to backtest? (±10% acceptable)\n- Is the drawdown within expected range?\n- Are there any technical issues (missed entries, wrong lot sizes)?\n- How does the EA behave around news events?\n\n**Pass criteria:**\n- 3+ months of forward testing\n- 50+ trades executed\n- Profit factor > 1.3 (slightly lower than backtest is normal)\n- Maximum drawdown within backtest range\n\nOnly after passing forward testing should you consider going live with real money.` },
      { title: 'Running EAs on a VPS', duration: '22 min', content: `A VPS (Virtual Private Server) is a remote computer that runs your MT4/5 and EA 24/7 without your local computer needing to be on.\n\n**Why use a VPS:**\n- Your EA keeps running when your computer is off\n- Uninterrupted internet connection (no internet drops)\n- Low latency to broker server (faster execution)\n- Power outages don't affect trading\n- No performance issues from running other programs\n\n**Minimum VPS specs for MT4/5:**\n- OS: Windows Server 2016/2019\n- RAM: 1-2 GB (more for multiple EAs)\n- CPU: 1-2 cores\n- Storage: 40 GB SSD\n- Network: 10 Mbps minimum, unlimited bandwidth\n- Location: Same city as your broker's server\n\n**Popular VPS providers for forex:**\n- ForexVPS.net (specialized for forex, low latency)\n- BeeksFX (popular with institutional traders)\n- Amazon AWS / Google Cloud (flexible but more setup)\n- MetaTrader4.com (MT4's own VPS service)\n\n**Setup steps:**\n1. Choose VPS provider close to your broker\n2. Log into VPS via Remote Desktop (Windows)\n3. Install MT4/5 on VPS\n4. Log in to your broker account\n5. Copy EA files to VPS\n6. Attach EA to chart and configure\n7. Verify EA is running correctly\n\n**Cost:** Quality forex VPS starts at $20-50/month.` },
      { title: 'Common EA Pitfalls', duration: '25 min', content: `Many traders lose money with EAs due to avoidable mistakes. Here are the most common pitfalls and how to avoid them.\n\n**1. Buying "magic" EAs**\nThe internet is full of EAs promising 1000% annual returns. 99% are scams or curve-fit systems that will blow accounts.\n- Rule: Never use an EA you don't understand completely\n- Rule: Backtest any purchased EA yourself before trusting vendor results\n\n**2. Martingale EAs**\nMartingale doubles position size after each loss to recover previous losses. Extremely dangerous.\n- A 7-trade losing streak at 1:2 doubling → position size 128× the original\n- Can blow an account in days\n- Avoid any EA that increases position size after losses\n\n**3. Grid trading EAs**\nOpens multiple trades at fixed price intervals, hoping the market ranges.\n- Fails catastrophically in trending markets\n- Often uses no stop losses\n- "Works" until it doesn't, then wipes the account\n\n**4. Backtesting with default spread**\nMT4's default spread in backtesting is often unrealistically low. Always set realistic spread (use your broker's average spread) in backtesting.\n\n**5. Not testing across market regimes**\nAn EA might perform great in trending markets but fail in ranging conditions. Test across various periods including 2020 (COVID crash), 2022 (high volatility), and low-volatility periods.\n\n**6. Ignoring slippage**\nAdd realistic slippage settings in your backtest to simulate real execution.` },
      { title: 'Community EA Resources', duration: '18 min', content: `The MetaTrader community has a vast ecosystem of resources for EA developers.\n\n**Code libraries and resources:**\n\n**MQL5.com Community:**\n- Largest MQL code library in the world\n- Free and paid EAs, indicators, scripts\n- Forums for code help\n- Signal service for copy trading\n\n**GitHub:**\nSearch for "MQL4 EA" or "MQL5 strategy" — many open-source trading systems available for study and modification.\n\n**Useful free indicators/EAs to study:**\n- ATR trailing stop\n- Market structure indicator\n- Session indicator (shows session ranges)\n- Economic calendar indicator\n\n**Learning MQL programming:**\n- MQL5.com documentation (comprehensive reference)\n- MetaEditor has built-in help (F1)\n- YouTube: search "MQL4 tutorial" or "MQL5 EA programming"\n\n**Backtesting data sources:**\n- Dukascopy (free historical tick data, excellent quality)\n- HistData.com (free 1M data going back to 2000)\n- MetaTrader's own data (download from broker, quality varies)\n\n**EA performance tracking:**\n- Myfxbook.com: Free, connects to MT4/5, tracks live performance automatically\n- FXBlue: Similar to Myfxbook with more detailed analytics\n\n**Community tip:** Before building an EA from scratch, search MQL5.com — someone has likely built something similar that you can study or modify.` },
      { title: 'Final Assessment', duration: '15 min', content: `Congratulations on completing Automated Trading & EAs! 🎉\n\n**Key takeaways:**\n\n✅ Automate only what you've proven profitable manually first\n✅ MT4 for simplicity, MT5 for advanced features\n✅ MQL structure: OnInit, OnDeinit, OnTick — learn these cold\n✅ Risk management in code is more reliable than manual (no emotion)\n✅ Backtest with 1+ years of data, 100+ trades, high-quality tick data\n✅ Optimize with walk-forward testing — avoid curve fitting\n✅ Forward test on demo for 3+ months before going live\n✅ Run live EAs on a VPS for 24/7 uptime\n✅ Avoid martingale and grid EAs — they will eventually blow accounts\n✅ MQL5.com is your primary resource for code, documentation, and community\n\n**Your next steps:**\n1. Install MT4 and MetaEditor\n2. Build and compile the MA crossover EA from Lesson 4\n3. Backtest it on EUR/USD 2020-2024\n4. Modify the entry conditions to match your own strategy\n5. Forward test for 30 days on demo\n\nYou now have the foundation to automate any rule-based trading strategy. Combine this with the Price Action course for maximum power. 🚀` },
    ],
  },
];

